mapper.select:
SELECT count(*) as all_count, sum( m.unbalance_alarm = 1 or m.misalignment_alarm = 1 or m.rotor_alarm = 1 or m.de_bpfo_alarm = 1 or m.DE_BPFI_alarm = 1 or m.DE_BSF_alarm = 1 or m.DE_FTF_alarm = 1 or m.NDE_BPFO_alarm = 1 or m.NDE_BPFI_alarm = 1 or m.NDE_BSF_alarm = 1 or m.NDE_FTF_alarm = 1 or m.DE_RMS_ALARM = 1 or m.NDE_RMS_ALARM = 1 or p.impeller_alarm = 1 or p.cavitation_alarm = 1 or p.de_bpfo_alarm = 1 or p.DE_BPFI_alarm = 1 or p.DE_BSF_alarm = 1 or p.DE_FTF_alarm = 1 or p.NDE_BPFO_alarm = 1 or p.NDE_BPFI_alarm = 1 or p.NDE_BSF_alarm = 1 or p.NDE_FTF_alarm =1 or m.DE_RMS_ALARM = 1 or m.NDE_RMS_ALARM = 1 ) as alarm, SUM( CASE WHEN m.DE_RMS_ALARM > 0 OR m.NDE_RMS_ALARM > 0 THEN 1 ELSE 0 END ) AS '펌프 총진동량', SUM( CASE WHEN m.DE_BPFO_ALARM > 0 OR m.DE_BPFI_ALARM > 0 OR m.DE_BSF_ALARM > 0 OR m.DE_FTF_ALARM > 0 OR m.NDE_BPFO_ALARM > 0 OR m.NDE_BPFI_ALARM > 0 OR m.NDE_BSF_ALARM > 0 OR m.NDE_FTF_ALARM > 0 THEN 1 ELSE 0 END ) AS '펌프 베어링', SUM( p.IMPELLER_ALARM ) AS '펌프 임펠러', SUM( p.CAVITATION_ALARM ) AS '펌프 케비테이션', SUM( m.MISALIGNMENT_ALARM ) AS '펌프모터 축정렬', SUM( m.UNBALANCE_ALARM ) AS '펌프모터 질량 불평형', SUM( CASE WHEN p.DE_RMS_ALARM > 0 OR m.NDE_RMS_ALARM > 0 THEN 1 ELSE 0 END ) AS '모터 총진동량', SUM( CASE WHEN p.DE_BPFO_ALARM > 0 OR p.DE_BPFI_ALARM > 0 OR p.DE_BSF_ALARM > 0 OR p.DE_FTF_ALARM > 0 OR p.NDE_BPFO_ALARM > 0 OR p.NDE_BPFI_ALARM > 0 OR p.NDE_BSF_ALARM > 0 OR p.NDE_FTF_ALARM > 0 THEN 1 ELSE 0 END ) AS '모터 베어링', SUM( m.ROTOR_ALARM ) AS '모터 회전자' FROM TB_AI_DIAG_MOTOR as m LEFT JOIN TB_AI_DIAG_PUMP as p on m.motor_id = p.PUMP_ID and m.ACQ_DATE = p.ACQ_DATE JOIN TB_PUMP_INF as tpi ON tpi.motor_id = p.PUMP_ID and tpi.motor_id = m.motor_id WHERE m.ACQ_DATE <= CONCAT(#{nowDate},' 23:59:59') and
m.ACQ_DATE >= DATE_SUB(CONCAT(DATE_FORMAT(#{nowDate}, '%Y-%m-%d'),' 00:00:00'), INTERVAL #{range} WEEK);
m.ACQ_DATE >= DATE_SUB(CONCAT(DATE_FORMAT(#{nowDate}, '%Y-%m-%d'),' 00:00:00'), INTERVAL #{range} MONTH);
